#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum AppIcon {
    Favorite,
    FavoriteFilled,
    Pin,
    PinFilled,
    File,
    Image,
    Delete,
}

impl AppIcon {
    fn path(self) -> &'static str {
        match self {
            Self::Favorite => FAVORITE_PATH,
            Self::FavoriteFilled => FAVORITE_FILLED_PATH,
            Self::Pin => PIN_PATH,
            Self::PinFilled => PIN_FILLED_PATH,
            Self::File => FILE_PATH,
            Self::Image => IMAGE_PATH,
            Self::Delete => DELETE_PATH,
        }
    }
}

#[component]
pub fn Icon(icon: AppIcon) -> Element {
    let path = icon.path();

    rsx! {
        svg {
            class: "app-icon",
            view_box: "0 0 1024 1024",
            path {
                d: "{path}",
                fill: "currentColor",
            }
        }
    }
}
